1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Step {
8	  type: string;
9	  items?: Item[];
10	  policy?: number;
11	  incident?: {
12	    cause: string;
13	    damages: { itemType: string; amount: number }[];
14	  };
15	}
16	
17	interface Scenario {
18	  customer: { years: number };
19	  steps: Step[];
20	}
21	
22	interface QuoteResult {
23	  premium: number;
24	}
25	
26	interface ClaimResult {
27	  payout: number;
28	  remainingCap: number;
29	}
30	
31	type Result = QuoteResult | ClaimResult;
32	
33	interface ScenarioOutput {
34	  results: Result[];
35	}
36	
37	const PROCESSING_FEE = 5;
38	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
39	const BUILDING_BLOCK_PREMIUM = 60;
40	const BUILDING_BLOCK_SIZE = 3;
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const LOYALTY_DISCOUNT_RATE = 0.2;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
47	
48	const BASE_PREMIUMS: Record<string, number> = {
49	  sword: 100,
50	  amulet: 60,
51	  staff: 80,
52	  potion: 40,
53	  rune: 25,
54	};
55	
56	const INSURANCE_VALUES: Record<string, number> = {
57	  sword: 1000,
58	  amulet: 600,
59	  staff: 800,
60	  potion: 400,
61	};
62	
63	const DEDUCTIBLE = 100;
64	const CAP_MULTIPLIER = 2;
65	
66	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
67	  const groups: Record<string, Item[]> = {};
68	  for (const item of items) {
69	    if (!groups[item.type]) {
70	      groups[item.type] = [];
71	    }
72	    groups[item.type].push(item);
73	  }
74	  return groups;
75	};
76	
77	const calculateSingleItemPremium = (item: Item): number => {
78	  const basePremium = BASE_PREMIUMS[item.type];
79	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
80	  const enchantmentSurcharge =
81	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
82	      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
83	      : 0;
84	  return basePremium + cursedSurcharge + enchantmentSurcharge;
85	};
86	
87	const calculateGroupPremium = (typeItems: Item[]): { total: number; base: number } => {
88	  if (typeItems.length === BUILDING_BLOCK_SIZE) {
89	    return { total: BUILDING_BLOCK_PREMIUM, base: BUILDING_BLOCK_PREMIUM };
90	  }
91	  return typeItems.reduce(
92	    (acc, item) => ({
93	      total: acc.total + calculateSingleItemPremium(item),
94	      base: acc.base + BASE_PREMIUMS[item.type],
95	    }),
96	    { total: 0, base: 0 },
97	  );
98	};
99	
100	const calculateItemsPremium = (items: Item[]): { total: number; base: number } => {
101	  const groups = Object.values(groupItemsByType(items));
102	  return groups.reduce(
103	    (acc, group) => {
104	      const groupResult = calculateGroupPremium(group);
105	      return { total: acc.total + groupResult.total, base: acc.base + groupResult.base };
106	    },
107	    { total: 0, base: 0 },
108	  );
109	};
110	
111	const calculateStepPremium = (
112	  step: Step,
113	  customerYears: number,
114	  isFollowUp: boolean,
115	): number => {
116	  const { total: itemsPremium, base: policyBasePremium } = calculateItemsPremium(step.items ?? []);
117	  const surcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
118	  const loyaltyDiscount =
119	    customerYears >= LOYALTY_YEARS_THRESHOLD
120	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
121	      : 0;
122	  const followUpDiscount = isFollowUp ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
123	  return Math.ceil(itemsPremium + surcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
124	};
125	
126	const calculateClaimResult = (step: Step, policyStep: Step): ClaimResult => {
127	  const policyItems = policyStep.items ?? [];
128	  const insuranceSum = policyItems.reduce(
129	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
130	    0,
131	  );
132	  const cap = insuranceSum * CAP_MULTIPLIER;
133	  const totalPayout = (step.incident?.damages ?? []).reduce(
134	    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
135	    0,
136	  );
137	  const cappedPayout = Math.min(totalPayout, cap);
138	  return { payout: cappedPayout, remainingCap: cap - cappedPayout };
139	};
140	
141	export function processScenario(scenario: Scenario): ScenarioOutput {
142	  const results = scenario.steps.map((step, index) => {
143	    if (step.type === "claim") {
144	      return calculateClaimResult(step, scenario.steps[step.policy!]);
145	    }
146	    const premium = calculateStepPremium(step, scenario.customer.years, index > 0);
147	    return { premium };
148	  });
149	  return { results };
150	}
